<?php namespace App\Http\Resources; use Illuminate\Http\Resources\Json\JsonResource; class UserResource extends JsonResource { public function toArray($req) { return ['id' => $this->id, 'email' => $this->email, 'firstName' => $this->first_name, 'lastName' => $this->last_name, 'isActive' => $this->is_active, 'roles' => $this->roles->pluck('slug'), 'groups' => $this->groups->pluck('slug'), 'permissions' => $this->getAllPermissions(), 'createdAt' => $this->created_at]; } }
